// A custom comparator matching the strict qsort signature.
// Uses void* to accept any type, casting it internally.
int compare_descending(const void *a, const void *b) {
    int val_a = *(const int *)a;
    int val_b = *(const int *)b;
    return (val_b - val_a); // Negative if A > B (Descending)
}

int main() {
    int data[] = {10, 5, 100, 42};
    size_t len = sizeof(data) / sizeof(data[0]);

    // qsort is oblivious to the data type. It delegates all comparison 
    // logic to the injected callback function.
    qsort(data, len, sizeof(int), compare_descending);

    for (size_t i = 0; i < len; i++) printf("%d ", data[i]);
    return 0;
}

