#include &lt;stdio.h&gt;

// 1. The Enum dictates the exact array indices (0, 1, 2)
typedef enum { STATE_INIT, STATE_RUN, STATE_STOP, NUM_STATES } State;

typedef State (*StateFunc)(void);

// 2. The State Handlers. They return the NEXT state to transition to.
State do_init() { printf("Booting...\n"); return STATE_RUN; }
State do_run()  { printf("Running...\n"); return STATE_STOP; }
State do_stop() { printf("Halting.\n");   return STATE_STOP; }

// 3. The Jump Table
StateFunc state_table[] = { do_init, do_run, do_stop };

int main() {
    State current = STATE_INIT;

    // 4. The Execution Loop. Zero conditional branching!
    for (int i = 0; i < 3; i++) {
        if (current >= NUM_STATES) break; // Guard clause
        current = state_table[current](); 
    }
    return 0;
}

#include &lt;stdio.h&gt;

// Real FSMs pass a 'Context' struct to share state between functions.
typedef struct { int speed; int temp; } Context;

// The function signature now requires the Context payload
typedef void (*StateAction)(Context *ctx);

void handle_idle(Context *ctx) { ctx->speed = 0; }
void handle_drive(Context *ctx) { ctx->speed += 10; }

int main() {
    // C99 Designated Initializers GUARANTEE sync, even if enum order changes!
    StateAction table[] = {
        [1] = handle_drive,
        [0] = handle_idle
    };

    Context my_car = {0, 0};
    table[1](&my_car); // Execute Drive state
    printf("Speed: %d\n", my_car.speed);
    return 0;
}

